        // File System Save Methods
        async saveBorderToFileSystem() {
            const createSubfolder = document.getElementById('borderCreateSubfolder')?.checked;
            const subfolderName = document.getElementById('borderSubfolderName')?.value || 'Border_Templates';

            if (!this.fileSystemStorage?.directoryHandle) {
                this.showToast('❌ Chưa cấp quyền File System!', 'error');
                return;
            }

            if (!this.borderTemplateData?.images || this.borderTemplateData.images.length === 0) {
                this.showToast('❌ Không có ảnh Border để lưu!', 'warning');
                return;
            }

            this.showToast('💾 Đang lưu Border Templates vào File System...', 'info');

            try {
                let savedCount = 0;
                const totalImages = this.borderTemplateData.images.length;
                const folderName = createSubfolder ? subfolderName : null;

                for (let i = 0; i < totalImages; i++) {
                    const imageData = this.borderTemplateData.images[i];

                    try {
                        // Tạo Border canvas với 300 DPI và chất lượng tối đa
                        const canvas = await this.createBorderCanvas(imageData);

                        // Convert canvas to blob với chất lượng 100% (không nén)
                        const blob = await new Promise((resolve, reject) => {
                            canvas.toBlob((blob) => {
                                if (blob) {
                                    resolve(blob);
                                } else {
                                    reject(new Error('Failed to create blob'));
                                }
                            }, 'image/jpeg', 1.0); // Quality 1.0 = 100%, không nén
                        });

                        // Thêm metadata 300 DPI
                        const enhancedBlob = await this.addDPIMetadata(blob, 300);

                        // Tạo tên file với index
                        const fileName = `Border_${String(i + 1).padStart(3, '0')}.jpg`;

                        // Lưu vào File System
                        await this.fileSystemStorage.saveImageToFileSystem(
                            enhancedBlob,
                            fileName,
                            folderName
                        );

                        savedCount++;

                        // Update progress
                        this.showToast(`💾 Đã lưu ${savedCount}/${totalImages} Border...`, 'info');

                    } catch (error) {
                        console.error(`❌ Lỗi lưu Border ${i + 1}:`, error);
                        // Continue with other images
                    }
                }

                // Success message
                if (savedCount > 0) {
                    const folderText = folderName ? ` trong thư mục "${folderName}"` : '';
                    this.showToast(`✅ Đã lưu thành công ${savedCount}/${totalImages} Border${folderText}!`, 'success');
                } else {
                    this.showToast('❌ Không thể lưu Border nào!', 'error');
                }

            } catch (error) {
                console.error('❌ Lỗi lưu Border Templates:', error);
                this.showToast('❌ Có lỗi xảy ra khi lưu Border Templates!', 'error');
            }
        }

